        const king = new King(this.color, this.row, this.col);
        king.hasMoved = this.hasMoved;
        return king;
    }
}

/**
 * Factory function to create pieces
 */
function createPiece(color, type, row, col) {
    switch (type) {
        case PieceType.PAWN:
            return new Pawn(color, row, col);
        case PieceType.ROOK:
            return new Rook(color, row, col);
        case PieceType.KNIGHT:
            return new Knight(color, row, col);
        case PieceType.BISHOP:
            return new Bishop(color, row, col);
        case PieceType.QUEEN:
            return new Queen(color, row, col);
        case PieceType.KING:
            return new King(color, row, col);
        default:
            throw new Error(`Unknown piece type: ${type}`);
    }
}

/**
 * Get piece symbol for display
 */
function getPieceSymbol(type, color) {
    const symbols = {
        white: {
            pawn: '♟',
            rook: '♜',
            knight: '♞',
            bishop: '♝',
            queen: '♛',
            king: '♚'
        },
        black: {
            pawn: '♙',
            rook: '♖',
            knight: '♘',
            bishop: '♗',
            queen: '♕',
            king: '♔'
        }
    };
    return symbols[color][type];
}

/**
 * Get piece value for evaluation
 */
function getPieceValue(type) {
    const values = {
        pawn: 1,
        knight: 3,
        bishop: 3,
        rook: 5,
        queen: 9,
        king: 0 // King is invaluable
    };
    return values[type];
}

