        this.initialize();
    }

    /**
     * Initialize the board with standard chess setup
     */
    initialize() {
        // Clear board
        this.grid = Array(8).fill(null).map(() => Array(8).fill(null));

        // Setup black pieces (top - rows 0-1)
        this.grid[0][0] = createPiece(PieceColor.BLACK, PieceType.ROOK, 0, 0);
        this.grid[0][1] = createPiece(PieceColor.BLACK, PieceType.KNIGHT, 0, 1);
        this.grid[0][2] = createPiece(PieceColor.BLACK, PieceType.BISHOP, 0, 2);
        this.grid[0][3] = createPiece(PieceColor.BLACK, PieceType.QUEEN, 0, 3);
        this.grid[0][4] = createPiece(PieceColor.BLACK, PieceType.KING, 0, 4);
        this.grid[0][5] = createPiece(PieceColor.BLACK, PieceType.BISHOP, 0, 5);
        this.grid[0][6] = createPiece(PieceColor.BLACK, PieceType.KNIGHT, 0, 6);
        this.grid[0][7] = createPiece(PieceColor.BLACK, PieceType.ROOK, 0, 7);

        for (let col = 0; col < 8; col++) {
            this.grid[1][col] = createPiece(PieceColor.BLACK, PieceType.PAWN, 1, col);
        }

        // Setup white pieces (bottom - rows 6-7)
        for (let col = 0; col < 8; col++) {
            this.grid[6][col] = createPiece(PieceColor.WHITE, PieceType.PAWN, 6, col);
        }

        this.grid[7][0] = createPiece(PieceColor.WHITE, PieceType.ROOK, 7, 0);
        this.grid[7][1] = createPiece(PieceColor.WHITE, PieceType.KNIGHT, 7, 1);
        this.grid[7][2] = createPiece(PieceColor.WHITE, PieceType.BISHOP, 7, 2);
        this.grid[7][3] = createPiece(PieceColor.WHITE, PieceType.QUEEN, 7, 3);
        this.grid[7][4] = createPiece(PieceColor.WHITE, PieceType.KING, 7, 4);
        this.grid[7][5] = createPiece(PieceColor.WHITE, PieceType.BISHOP, 7, 5);
        this.grid[7][6] = createPiece(PieceColor.WHITE, PieceType.KNIGHT, 7, 6);
        this.grid[7][7] = createPiece(PieceColor.WHITE, PieceType.ROOK, 7, 7);

        this.enPassantTarget = null;
        this.halfMoveClock = 0;
        this.fullMoveNumber = 1;
    }

    /**
     * Get piece at position
     * @param {number} row - Row index
     * @param {number} col - Column index
     * @returns {Piece|null} Piece at position or null
     */
    getPieceAt(row, col) {
        if (!Position.isValid(row, col)) {
            return null;
        }
        return this.grid[row][col];
    }

    /**
     * Set piece at position
     * @param {number} row - Row index
     * @param {number} col - Column index
     * @param {Piece} piece - Piece to place
     */
    setPieceAt(row, col, piece) {
        if (Position.isValid(row, col)) {
            this.grid[row][col] = piece;
            if (piece) {
                piece.row = row;
                piece.col = col;
            }
        }
    }

    /**
     * Move piece from one position to another
     * @param {Object} from - Source position {row, col}
     * @param {Object} to - Destination position {row, col}
     * @returns {Piece|null} Captured piece or null
     */
    movePiece(from, to) {
        const piece = this.getPieceAt(from.row, from.col);
        const captured = this.getPieceAt(to.row, to.col);

        this.setPieceAt(from.row, from.col, null);
        this.setPieceAt(to.row, to.col, piece);

        if (piece) {
            piece.hasMoved = true;
        }

        return captured;
    }

    /**
     * Find king for a color
     * @param {string} color - Piece color
     * @returns {Object|null} King position {row, col} or null
     */
    findKing(color) {
        for (let row = 0; row < 8; row++) {
            for (let col = 0; col < 8; col++) {
                const piece = this.grid[row][col];
                if (piece && piece.color === color && piece.type === PieceType.KING) {
                    return { row, col };
                }
            }
        }
        return null;
    }

    /**
     * Get all pieces for a color
     * @param {string} color - Piece color
     * @returns {Array} Array of pieces with positions
     */
    getPiecesForColor(color) {
        const pieces = [];
        for (let row = 0; row < 8; row++) {
            for (let col = 0; col < 8; col++) {
                const piece = this.grid[row][col];
                if (piece && piece.color === color) {
                    pieces.push({ piece, row, col });
                }
            }
        }
        return pieces;
    }

    /**
     * Check if a position is under attack by a color
     * @param {Object} pos - Position to check {row, col}
     * @param {string} attackerColor - Color of attacking pieces
     * @returns {boolean} True if position is under attack
     */
    isPositionUnderAttack(pos, attackerColor) {
        const enemyPieces = this.getPiecesForColor(attackerColor);

        for (const { piece, row, col } of enemyPieces) {
            const moves = piece.getValidMoves(this);
            for (const move of moves) {
                if (move.row === pos.row && move.col === pos.col) {
                    return true;
                }
            }
        }

        return false;
    }

    /**
     * Clone the board
     * @returns {Board} New board with same state
     */
    clone() {
        const newBoard = new Board();
        newBoard.grid = this.grid.map(row =>
            row.map(piece => piece ? piece.clone() : null)
        );
        newBoard.enPassantTarget = this.enPassantTarget;
        newBoard.halfMoveClock = this.halfMoveClock;
        newBoard.fullMoveNumber = this.fullMoveNumber;
        return newBoard;
    }

    /**
     * Serialize board to FEN notation
     * @returns {string} FEN string
     */
    toFEN() {
        let fen = '';

        for (let row = 0; row < 8; row++) {
            let emptyCount = 0;
            for (let col = 0; col < 8; col++) {
                const piece = this.grid[row][col];
                if (piece) {
                    if (emptyCount > 0) {
                        fen += emptyCount;
                        emptyCount = 0;
                    }
                    const symbol = getPieceSymbol(piece.type, piece.color);
                    fen += piece.color === PieceColor.WHITE ? symbol.toUpperCase() : symbol.toLowerCase();
                } else {
                    emptyCount++;
                }
            }
            if (emptyCount > 0) {
                fen += emptyCount;
            }
            if (row < 7) {
                fen += '/';
            }
        }

        return fen;
    }

    /**
     * Get board state as plain object for UI
     * @returns {Object} Board state
     */
    getState() {
        const state = {
            grid: [],
            enPassantTarget: this.enPassantTarget,
            halfMoveClock: this.halfMoveClock,
            fullMoveNumber: this.fullMoveNumber
        };

        for (let row = 0; row < 8; row++) {
            const rowData = [];
            for (let col = 0; col < 8; col++) {
                const piece = this.grid[row][col];
                if (piece) {
                    rowData.push({
                        color: piece.color,
                        type: piece.type,
                        hasMoved: piece.hasMoved
                    });
                } else {
                    rowData.push(null);
                }
            }
            state.grid.push(rowData);
        }

        return state;
    }
}

