/**
 * Chess rules validation
 * Handles check, checkmate, special moves, and move validation
 */

class Rules {
    /**
     * Validate a move and return if it's legal
     * @param {Board} board - The game board
     * @param {Object} from - Source position
     * @param {Object} to - Destination position
     * @param {string} color - Color of player making move
     * @returns {Object} Validation result {valid, reason, moveType}
     */
    static validateMove(board, from, to, color) {
        const piece = board.getPieceAt(from.row, from.col);

        // Check if there's a piece at source
        if (!piece) {
            return { valid: false, reason: 'No piece at source position' };
        }

        // Check if piece belongs to current player
        if (piece.color !== color) {
            return { valid: false, reason: 'Not your piece' };
        }

        // Get all valid moves for this piece
        const validMoves = piece.getValidMoves(board);

        // Check if destination is in valid moves
        const isValidDestination = validMoves.some(move =>
            move.row === to.row && move.col === to.col
        );

        if (!isValidDestination) {
            return { valid: false, reason: 'Invalid move for this piece' };
        }

        // Check if move would leave king in check
        const clonedBoard = board.clone();
        clonedBoard.movePiece(from, to);

        // Handle en passant capture
        if (to.isEnPassant) {
            const captureRow = from.row;
            const captureCol = to.col;
            clonedBoard.setPieceAt(captureRow, captureCol, null);
        }

        const kingPos = clonedBoard.findKing(color);
        if (!kingPos) {
            return { valid: false, reason: 'King not found' };
        }

        const enemyColor = color === PieceColor.WHITE ? PieceColor.BLACK : PieceColor.WHITE;
        if (clonedBoard.isPositionUnderAttack(kingPos, enemyColor)) {
            return { valid: false, reason: 'Would leave king in check' };
        }

        // Determine move type
        let moveType = 'normal';

        // Check for castling
        if (piece.type === PieceType.KING && Math.abs(to.col - from.col) === 2) {
            moveType = 'castling';
        }

        // Check for en passant
        if (to.isEnPassant) {
            moveType = 'enpassant';
        }

        // Check for pawn promotion
        if (piece.type === PieceType.PAWN) {
            if ((color === PieceColor.WHITE && to.row === 0) ||
                (color === PieceColor.BLACK && to.row === 7)) {
                moveType = 'promotion';
            }
        }

        return { valid: true, moveType };
    }

    /**
     * Check if a king is in check
     * @param {Board} board - The game board
     * @param {string} color - Color of king to check
     * @returns {boolean} True if king is in check
     */
    static isCheck(board, color) {
        const kingPos = board.findKing(color);
        if (!kingPos) {
            return false;
        }

        const enemyColor = color === PieceColor.WHITE ? PieceColor.BLACK : PieceColor.WHITE;
        return board.isPositionUnderAttack(kingPos, enemyColor);
    }

    /**
     * Check if a player is in checkmate
     * @param {Board} board - The game board
     * @param {string} color - Color of player to check
     * @returns {boolean} True if checkmate
     */
    static isCheckmate(board, color) {
        if (!this.isCheck(board, color)) {
            return false;
        }

        return !this.hasAnyLegalMoves(board, color);
    }

    /**
     * Check if a player is in stalemate
     * @param {Board} board - The game board
     * @param {string} color - Color of player to check
     * @returns {boolean} True if stalemate
     */
    static isStalemate(board, color) {
        if (this.isCheck(board, color)) {
            return false;
        }

        return !this.hasAnyLegalMoves(board, color);
    }

    /**
     * Check if player has any legal moves
     * @param {Board} board - The game board
     * @param {string} color - Color of player to check
     * @returns {boolean} True if has legal moves
     */
    static hasAnyLegalMoves(board, color) {
        const pieces = board.getPiecesForColor(color);

        for (const { piece, row, col } of pieces) {
            const moves = piece.getValidMoves(board);

            for (const move of moves) {
                const result = this.validateMove(board, { row, col }, move, color);
                if (result.valid) {
                    return true;
                }
            }
        }

        return false;
    }

    /**
     * Check if castling is available
     * @param {Board} board - The game board
     * @param {string} color - Color of player
     * @param {boolean} kingSide - True for king side, false for queen side
     * @returns {boolean} True if castling is available
     */
    static canCastle(board, color, kingSide) {
        const king = board.findKing(color);
        if (!king) {
            return false;
        }

        const kingPiece = board.getPieceAt(king.row, king.col);
        if (!kingPiece || kingPiece.hasMoved) {
            return false;
        }

        // Check if king is in check
        if (this.isCheck(board, color)) {
            return false;
        }

        const enemyColor = color === PieceColor.WHITE ? PieceColor.BLACK : PieceColor.WHITE;
        const row = color === PieceColor.WHITE ? 7 : 0;

        if (kingSide) {
            // King side castling
            const rookCol = 7;
            const rook = board.getPieceAt(row, rookCol);

            if (!rook || rook.type !== PieceType.ROOK || rook.hasMoved) {
                return false;
            }

            // Check if squares between king and rook are empty
            for (let col = 5; col <= 6; col++) {
                if (board.getPieceAt(row, col)) {
                    return false;
                }
            }

            // Check if king passes through or lands on attacked square
            if (board.isPositionUnderAttack({ row, col: 5 }, enemyColor) ||
                board.isPositionUnderAttack({ row, col: 6 }, enemyColor)) {
                return false;
            }

            return true;
        } else {
            // Queen side castling
            const rookCol = 0;
            const rook = board.getPieceAt(row, rookCol);

            if (!rook || rook.type !== PieceType.ROOK || rook.hasMoved) {
                return false;
            }

            // Check if squares between king and rook are empty
            for (let col = 1; col <= 3; col++) {
                if (board.getPieceAt(row, col)) {
                    return false;
                }
            }

            // Check if king passes through or lands on attacked square
            if (board.isPositionUnderAttack({ row, col: 2 }, enemyColor) ||
                board.isPositionUnderAttack({ row, col: 3 }, enemyColor)) {
                return false;
            }

            return true;
        }
    }

    /**
     * Get castling move
     * @param {Board} board - The game board
     * @param {string} color - Color of player
     * @param {boolean} kingSide - True for king side, false for queen side
     * @returns {Object|null} Castling move {from, to, rookFrom, rookTo} or null
     */
    static getCastlingMove(board, color, kingSide) {
        if (!this.canCastle(board, color, kingSide)) {
            return null;
        }

        const row = color === PieceColor.WHITE ? 7 : 0;
        const kingCol = 4;

        if (kingSide) {
            return {
                from: { row, col: kingCol },
                to: { row, col: 6 },
                rookFrom: { row, col: 7 },
                rookTo: { row, col: 5 }
            };
        } else {
            return {
                from: { row, col: kingCol },
                to: { row, col: 2 },
                rookFrom: { row, col: 0 },
                rookTo: { row, col: 3 }
            };
        }
    }

    /**
     * Get all legal moves for a piece at position
     * @param {Board} board - The game board
     * @param {Object} pos - Position {row, col}
     * @returns {Array} Array of valid move positions
     */
    static getLegalMoves(board, pos) {
        const piece = board.getPieceAt(pos.row, pos.col);
        if (!piece) {
            return [];
        }

        const pseudoLegalMoves = piece.getValidMoves(board);
        const legalMoves = [];

        for (const move of pseudoLegalMoves) {
            const result = this.validateMove(board, pos, move, piece.color);
            if (result.valid) {
                legalMoves.push({
                    ...move,
                    moveType: result.moveType
                });
            }
        }

        // Add castling moves for king
        if (piece.type === PieceType.KING) {
            if (this.canCastle(board, piece.color, true)) {
                legalMoves.push({
                    row: pos.row,
                    col: pos.col + 2,
                    moveType: 'castling',
                    castleSide: 'king'
                });
            }
            if (this.canCastle(board, piece.color, false)) {
                legalMoves.push({
                    row: pos.row,
                    col: pos.col - 2,
                    moveType: 'castling',
                    castleSide: 'queen'
                });
            }
        }

        return legalMoves;
    }

    /**
     * Get game state
     * @param {Board} board - The game board
     * @param {string} currentColor - Current player's color
     * @returns {Object} Game state {status, winner, inCheck}
     */
    static getGameState(board, currentColor) {
        const inCheck = this.isCheck(board, currentColor);

        if (this.isCheckmate(board, currentColor)) {
            const winner = currentColor === PieceColor.WHITE ? 'black' : 'white';
            return {
                status: 'checkmate',
                winner: winner,
                inCheck: true
            };
        }

        if (this.isStalemate(board, currentColor)) {
            return {
                status: 'stalemate',
                winner: null,
                inCheck: false
            };
        }

        return {
            status: 'playing',
            winner: null,
            inCheck: inCheck
        };
    }
}

