/**
 * Game of Thrones Theme for The Game of Chess
 * Defines colors, symbols, and visual styling for GoT themed chess
 */

const GoTTheme = {
    // Color palette
    colors: {
        // Board colors
        boardDark: '#2d3436',
        boardLight: '#636e72',
        boardBorder: '#c9a227',

        // White pieces (Noble Houses)
        whitePrimary: '#b0bec5',
        whiteSecondary: '#4a4a4a',
        whiteAccent: '#1e3a5f', // Stark blue
        whiteGlow: 'rgba(30, 58, 95, 0.3)',

        // Black pieces (White Walkers)
        blackPrimary: '#e3f2fd',
        blackSecondary: '#0288d1',
        blackAccent: '#4fc3f7', // Ice blue
        blackGlow: 'rgba(79, 195, 247, 0.4)',

        // UI highlights
        highlightValid: 'rgba(76, 175, 80, 0.5)',
        highlightSelected: 'rgba(255, 193, 7, 0.6)',
        highlightCheck: 'rgba(244, 67, 54, 0.7)',
        highlightLastMove: 'rgba(155, 89, 182, 0.4)',

        // Special colors
        targaryenRed: '#8b0000',
        lannisterGold: '#c9a227',
        nightKingBlue: '#01579b'
    },

    // Piece symbols (heraldic/GoT themed)
    pieceSymbols: {
        white: {
            pawn: '🛡️',      // Shield
            rook: '🏰',       // Castle/Tower
            knight: '🐺',     // Direwolf (Stark)
            bishop: '🌲',     // Weirwood tree
            queen: '🐉',      // Dragon (Targaryen)
            king: '👑'        // Iron Throne crown
        },
        black: {
            pawn: '❄️',       // Snowflake
            rook: '🧊',       // Ice block
            knight: '💀',     // Skull
            bishop: '👁️',     // Night King eye
            queen: '🌨️',      // Blizzard
            king: '🧛'        // Night King
        }
    },

    // Alternative piece symbols (unicode chess pieces for fallback)
    chessSymbols: {
        white: {
            pawn: '♙', rook: '♖', knight: '♘', bishop: '♗', queen: '♕', king: '♔'
        },
        black: {
            pawn: '♟', rook: '♜', knight: '♞', bishop: '♝', queen: '♛', king: '♚'
        }
    },

    // House banners for decoration
    houses: {
        stark: { name: 'Stark', color: '#1e3a5f', symbol: '🐺' },
        lannister: { name: 'Lannister', color: '#c9a227', symbol: '🦁' },
        targaryen: { name: 'Targaryen', color: '#8b0000', symbol: '🐉' },
        baratheon: { name: 'Baratheon', color: '#2d3436', symbol: '🦌' },
        nightKing: { name: 'Night King', color: '#01579b', symbol: '🧛' }
    },

    // Board texture patterns
    patterns: {
        // Dark square pattern - stone texture
        darkSquare: (ctx, x, y, size) => {
            // Base color
            ctx.fillStyle = '#2d3436';
            ctx.fillRect(x, y, size, size);

            // Add subtle texture
            ctx.fillStyle = 'rgba(0, 0, 0, 0.1)';
            for (let i = 0; i < 5; i++) {
                const px = x + Math.random() * size;
                const py = y + Math.random() * size;
                ctx.beginPath();
                ctx.arc(px, py, 1 + Math.random() * 2, 0, Math.PI * 2);
                ctx.fill();
            }

            // Add frost pattern for black side
            ctx.strokeStyle = 'rgba(79, 195, 247, 0.1)';
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(x + size * 0.2, y + size * 0.8);
            ctx.lineTo(x + size * 0.5, y + size * 0.5);
            ctx.lineTo(x + size * 0.8, y + size * 0.2);
            ctx.stroke();
        },

        // Light square pattern - weathered wood
        lightSquare: (ctx, x, y, size) => {
            // Base color
            ctx.fillStyle = '#636e72';
            ctx.fillRect(x, y, size, size);

            // Add wood grain texture
            ctx.strokeStyle = 'rgba(0, 0, 0, 0.05)';
            ctx.lineWidth = 1;
            for (let i = 0; i < 3; i++) {
                const offset = (i + 1) * size * 0.2;
                ctx.beginPath();
                ctx.moveTo(x, y + offset);
                ctx.lineTo(x + size, y + offset);
                ctx.stroke();
            }

            // Add subtle highlights
            ctx.fillStyle = 'rgba(255, 255, 255, 0.05)';
            ctx.fillRect(x, y, size, size * 0.1);
        }
    },

    // Get piece symbol based on type and color
    getPieceSymbol(type, color) {
        return this.pieceSymbols[color][type];
    },

    // Get chess symbol (fallback)
    getChessSymbol(type, color) {
        return this.chessSymbols[color][type];
    },

    // Get piece color scheme
    getPieceColors(color) {
        if (color === 'white') {
            return {
                primary: this.colors.whitePrimary,
                secondary: this.colors.whiteSecondary,
                accent: this.colors.whiteAccent,
                glow: this.colors.whiteGlow
            };
        } else {
            return {
                primary: this.colors.blackPrimary,
                secondary: this.colors.blackSecondary,
                accent: this.colors.blackAccent,
                glow: this.colors.blackGlow
            };
        }
    },

    // Draw GoT themed piece on canvas
    drawPiece(ctx, type, color, x, y, size) {
        const colors = this.getPieceColors(color);
        const centerX = x + size / 2;
        const centerY = y + size / 2;
        const pieceSize = size * 0.7;

        // Draw glow effect
        ctx.save();
        ctx.shadowColor = colors.accent;
        ctx.shadowBlur = 10;
        ctx.shadowOffsetX = 0;
        ctx.shadowOffsetY = 0;

        // Draw base circle
        ctx.beginPath();
        ctx.arc(centerX, centerY, pieceSize / 2, 0, Math.PI * 2);
        ctx.fillStyle = colors.primary;
        ctx.fill();

        // Draw border
        ctx.strokeStyle = colors.accent;
        ctx.lineWidth = 2;
        ctx.stroke();

        ctx.restore();

        // Draw inner design based on piece type
        ctx.save();
        ctx.translate(centerX, centerY);

        switch (type) {
            case 'pawn':
                this.drawPawnSymbol(ctx, color, pieceSize);
                break;
            case 'rook':
                this.drawRookSymbol(ctx, color, pieceSize);
                break;
            case 'knight':
                this.drawKnightSymbol(ctx, color, pieceSize);
                break;
            case 'bishop':
                this.drawBishopSymbol(ctx, color, pieceSize);
                break;
            case 'queen':
                this.drawQueenSymbol(ctx, color, pieceSize);
                break;
            case 'king':
                this.drawKingSymbol(ctx, color, pieceSize);
                break;
        }

        ctx.restore();
    },

    // Draw heraldic symbols for each piece type
    drawPawnSymbol(ctx, color, size) {
        const colors = this.getPieceColors(color);

        // Shield shape
        ctx.beginPath();
        ctx.moveTo(0, -size * 0.3);
        ctx.lineTo(size * 0.25, -size * 0.1);
        ctx.lineTo(size * 0.25, size * 0.2);
        ctx.lineTo(0, size * 0.35);
        ctx.lineTo(-size * 0.25, size * 0.2);
        ctx.lineTo(-size * 0.25, -size * 0.1);
        ctx.closePath();

        ctx.fillStyle = colors.secondary;
        ctx.fill();
        ctx.strokeStyle = colors.accent;
        ctx.lineWidth = 2;
        ctx.stroke();

        // Inner detail
        ctx.beginPath();
        ctx.arc(0, 0, size * 0.1, 0, Math.PI * 2);
        ctx.fillStyle = colors.accent;
        ctx.fill();
    },

    drawRookSymbol(ctx, color, size) {
        const colors = this.getPieceColors(color);

        // Castle tower
        ctx.fillStyle = colors.secondary;
        ctx.fillRect(-size * 0.25, -size * 0.3, size * 0.5, size * 0.6);

        // Battlements
        ctx.fillRect(-size * 0.3, -size * 0.35, size * 0.15, size * 0.1);
        ctx.fillRect(-size * 0.08, -size * 0.35, size * 0.16, size * 0.1);
        ctx.fillRect(size * 0.15, -size * 0.35, size * 0.15, size * 0.1);

        // Door
        ctx.fillStyle = colors.accent;
        ctx.fillRect(-size * 0.1, size * 0.1, size * 0.2, size * 0.2);
    },

    drawKnightSymbol(ctx, color, size) {
        const colors = this.getPieceColors(color);

        // Horse helm silhouette
        ctx.beginPath();
        ctx.moveTo(-size * 0.2, size * 0.3);
        ctx.lineTo(-size * 0.3, size * 0.1);
        ctx.lineTo(-size * 0.25, -size * 0.1);
        ctx.lineTo(-size * 0.1, -size * 0.25);
        ctx.lineTo(size * 0.1, -size * 0.3);
        ctx.lineTo(size * 0.25, -size * 0.2);
        ctx.lineTo(size * 0.3, size * 0.1);
        ctx.lineTo(size * 0.2, size * 0.3);
        ctx.closePath();

        ctx.fillStyle = colors.secondary;
        ctx.fill();
        ctx.strokeStyle = colors.accent;
        ctx.lineWidth = 2;
        ctx.stroke();

        // Eye
        ctx.beginPath();
        ctx.arc(size * 0.15, -size * 0.1, size * 0.05, 0, Math.PI * 2);
        ctx.fillStyle = colors.accent;
        ctx.fill();
    },

    drawBishopSymbol(ctx, color, size) {
        const colors = this.getPieceColors(color);

        // Weirwood tree / crown shape
        ctx.beginPath();
        ctx.moveTo(0, -size * 0.35);
        ctx.lineTo(-size * 0.2, -size * 0.1);
        ctx.lineTo(-size * 0.15, size * 0.1);
        ctx.lineTo(-size * 0.25, size * 0.3);
        ctx.lineTo(size * 0.25, size * 0.3);
        ctx.lineTo(size * 0.15, size * 0.1);
        ctx.lineTo(size * 0.2, -size * 0.1);
        ctx.closePath();

        ctx.fillStyle = colors.secondary;
        ctx.fill();
        ctx.strokeStyle = colors.accent;
        ctx.lineWidth = 2;
        ctx.stroke();

        // Leaves/branches
        for (let i = 0; i < 3; i++) {
            const angle = (i - 1) * Math.PI / 6;
            ctx.beginPath();
            ctx.moveTo(0, -size * 0.1);
            ctx.lineTo(
                Math.sin(angle) * size * 0.2,
                -size * 0.1 - Math.cos(angle) * size * 0.15
            );
            ctx.strokeStyle = colors.accent;
            ctx.lineWidth = 1.5;
            ctx.stroke();
        }
    },

    drawQueenSymbol(ctx, color, size) {
        const colors = this.getPieceColors(color);

        // Dragon silhouette (simplified)
        ctx.beginPath();
        // Body
        ctx.ellipse(0, size * 0.1, size * 0.15, size * 0.2, 0, 0, Math.PI * 2);
        // Head
        ctx.moveTo(size * 0.1, -size * 0.05);
        ctx.lineTo(size * 0.25, -size * 0.15);
        ctx.lineTo(size * 0.2, -size * 0.05);
        // Wing
        ctx.moveTo(-size * 0.1, 0);
        ctx.lineTo(-size * 0.35, -size * 0.2);
        ctx.lineTo(-size * 0.3, size * 0.1);
        // Tail
        ctx.moveTo(-size * 0.1, size * 0.25);
        ctx.lineTo(-size * 0.25, size * 0.35);

        ctx.fillStyle = colors.secondary;
        ctx.fill();
        ctx.strokeStyle = colors.accent;
        ctx.lineWidth = 2;
        ctx.stroke();

        // Eye
        ctx.beginPath();
        ctx.arc(size * 0.15, -size * 0.1, size * 0.03, 0, Math.PI * 2);
        ctx.fillStyle = colors.accent;
        ctx.fill();
    },

    drawKingSymbol(ctx, color, size) {
        const colors = this.getPieceColors(color);

        // Iron Throne / Crown shape
        ctx.beginPath();
        // Base
        ctx.moveTo(-size * 0.25, size * 0.3);
        ctx.lineTo(size * 0.25, size * 0.3);
        // Left side
        ctx.lineTo(size * 0.2, -size * 0.1);
        ctx.lineTo(size * 0.1, -size * 0.2);
        // Top
        ctx.lineTo(0, -size * 0.35);
        ctx.lineTo(-size * 0.1, -size * 0.2);
        // Right side
        ctx.lineTo(-size * 0.2, -size * 0.1);
        ctx.closePath();

        ctx.fillStyle = colors.secondary;
        ctx.fill();
        ctx.strokeStyle = colors.accent;
        ctx.lineWidth = 2;
        ctx.stroke();

        // Swords on throne
        for (let i = 0; i < 5; i++) {
            const offset = (i - 2) * size * 0.08;
            ctx.beginPath();
            ctx.moveTo(offset, size * 0.3);
            ctx.lineTo(offset, -size * 0.15 + Math.abs(offset) * 0.3);
            ctx.strokeStyle = colors.accent;
            ctx.lineWidth = 1;
            ctx.stroke();
        }

        // Gem
        ctx.beginPath();
        ctx.arc(0, 0, size * 0.08, 0, Math.PI * 2);
        ctx.fillStyle = this.colors.lannisterGold;
        ctx.fill();
    },

    // Draw highlight on square
    drawHighlight(ctx, x, y, size, type) {
        let color;
        switch (type) {
            case 'valid':
                color = this.colors.highlightValid;
                break;
            case 'selected':
                color = this.colors.highlightSelected;
                break;
            case 'check':
                color = this.colors.highlightCheck;
                break;
            case 'lastMove':
                color = this.colors.highlightLastMove;
                break;
            default:
                return;
        }

        ctx.fillStyle = color;
        ctx.fillRect(x, y, size, size);

        // Add border for check
        if (type === 'check') {
            ctx.strokeStyle = '#f44336';
            ctx.lineWidth = 3;
            ctx.strokeRect(x + 2, y + 2, size - 4, size - 4);
        }
    },

    // Draw move indicator dot
    drawMoveIndicator(ctx, x, y, size, isCapture) {
        const centerX = x + size / 2;
        const centerY = y + size / 2;
        const radius = size * 0.15;

        if (isCapture) {
            // Capture indicator - ring
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
            ctx.strokeStyle = 'rgba(76, 175, 80, 0.8)';
            ctx.lineWidth = 4;
            ctx.stroke();
        } else {
            // Move indicator - filled dot
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(76, 175, 80, 0.6)';
            ctx.fill();
        }
    }
};

