/**
 * Input handler for chess game
 * Manages mouse and touch interactions with the board
 */

class InputHandler {
    constructor(canvas, renderer, gameEngine) {
        this.canvas = canvas;
        this.renderer = renderer;
        this.gameEngine = gameEngine;

        this.selectedPiece = null;
        this.isDragging = false;
        this.dragStartPos = null;

        this.setupEventListeners();
    }

    /**
     * Setup mouse and touch event listeners
     */
    setupEventListeners() {
        // Mouse events
        this.canvas.addEventListener('click', this.handleClick.bind(this));
        this.canvas.addEventListener('mousemove', this.handleMouseMove.bind(this));
        this.canvas.addEventListener('mouseleave', this.handleMouseLeave.bind(this));

        // Touch events
        this.canvas.addEventListener('touchstart', this.handleTouchStart.bind(this), { passive: false });
        this.canvas.addEventListener('touchmove', this.handleTouchMove.bind(this), { passive: false });
        this.canvas.addEventListener('touchend', this.handleTouchEnd.bind(this), { passive: false });

        // Prevent context menu on right click
        this.canvas.addEventListener('contextmenu', (e) => e.preventDefault());
    }

    /**
     * Handle mouse click
     * @param {MouseEvent} e - Mouse event
     */
    handleClick(e) {
        if (this.gameEngine.gameState.status !== 'playing') {
            return;
        }

        const pos = this.renderer.canvasToBoard(e.clientX, e.clientY);

        if (!Position.isValid(pos.row, pos.col)) {
            this.deselectPiece();
            return;
        }

        this.handleSquareClick(pos);
    }

    /**
     * Handle mouse move for hover effects
     * @param {MouseEvent} e - Mouse event
     */
    handleMouseMove(e) {
        const pos = this.renderer.canvasToBoard(e.clientX, e.clientY);

        if (Position.isValid(pos.row, pos.col)) {
            this.renderer.setHoveredSquare(pos);
            this.renderer.render();
        } else {
            this.renderer.setHoveredSquare(null);
            this.renderer.render();
        }
    }

    /**
     * Handle mouse leaving canvas
     */
    handleMouseLeave() {
        this.renderer.setHoveredSquare(null);
        this.renderer.render();
    }

    /**
     * Handle touch start
     * @param {TouchEvent} e - Touch event
     */
    handleTouchStart(e) {
        e.preventDefault();

        if (this.gameEngine.gameState.status !== 'playing') {
            return;
        }

        const touch = e.touches[0];
        const pos = this.renderer.canvasToBoard(touch.clientX, touch.clientY);

        if (!Position.isValid(pos.row, pos.col)) {
            return;
        }

        this.isDragging = true;
        this.dragStartPos = pos;
    }

    /**
     * Handle touch move
     * @param {TouchEvent} e - Touch event
     */
    handleTouchMove(e) {
        e.preventDefault();

        if (!this.isDragging) {
            return;
        }

        const touch = e.touches[0];
        const pos = this.renderer.canvasToBoard(touch.clientX, touch.clientY);

        if (Position.isValid(pos.row, pos.col)) {
            this.renderer.setHoveredSquare(pos);
            this.renderer.render();
        }
    }

    /**
     * Handle touch end
     * @param {TouchEvent} e - Touch event
     */
    handleTouchEnd(e) {
        e.preventDefault();

        if (!this.isDragging || !this.dragStartPos) {
            return;
        }

        const touch = e.changedTouches[0];
        const pos = this.renderer.canvasToBoard(touch.clientX, touch.clientY);

        if (Position.isValid(pos.row, pos.col)) {
            this.handleSquareClick(pos);
        }

        this.isDragging = false;
        this.dragStartPos = null;
    }

    /**
     * Handle clicking on a square
     * @param {Object} pos - Board position {row, col}
     */
    handleSquareClick(pos) {
        const clickedPiece = this.gameEngine.board.getPieceAt(pos.row, pos.col);

        // If we have a selected piece, try to move
        if (this.selectedPiece) {
            // Check if clicking on valid move
            const isValidMove = this.renderer.validMoves.some(
                move => move.row === pos.row && move.col === pos.col
            );

            if (isValidMove) {
                this.executeMove(this.selectedPiece, pos);
                return;
            }

            // If clicking on own piece, select it instead
            if (clickedPiece && clickedPiece.color === this.gameEngine.currentTurn) {
                this.selectPiece(pos);
                return;
            }

            // Otherwise, deselect
            this.deselectPiece();
            return;
        }

        // If no piece selected, try to select one
        if (clickedPiece && clickedPiece.color === this.gameEngine.currentTurn) {
            this.selectPiece(pos);
        }
    }

    /**
     * Select a piece
     * @param {Object} pos - Position {row, col}
     */
    selectPiece(pos) {
        const piece = this.gameEngine.board.getPieceAt(pos.row, pos.col);

        if (!piece || piece.color !== this.gameEngine.currentTurn) {
            return;
        }

        this.selectedPiece = { ...pos, piece };
        this.renderer.setSelectedSquare(pos);

        // Get and display valid moves
        const validMoves = Rules.getLegalMoves(this.gameEngine.board, pos);
        this.renderer.setValidMoves(validMoves);

        this.renderer.render();
    }

    /**
     * Deselect current piece
     */
    deselectPiece() {
        this.selectedPiece = null;
        this.renderer.setSelectedSquare(null);
        this.renderer.setValidMoves([]);
        this.renderer.render();
    }

    /**
     * Execute a move
     * @param {Object} from - Source position
     * @param {Object} to - Destination position
     */
    async executeMove(from, to) {
        const moveResult = this.gameEngine.makeMove(from, to);

        if (moveResult.success) {
            this.deselectPiece();

            // Update renderer with last move
            this.renderer.setLastMove({
                from: { row: from.row, col: from.col },
                to: { row: to.row, col: to.col }
            });

            // Check for check and show alert
            if (this.gameEngine.gameState.inCheck) {
                this.renderer.triggerCheckAlert();
            }

            this.renderer.render();
        }
    }

    /**
     * Reset the input handler state
     */
    reset() {
        this.deselectPiece();
        this.isDragging = false;
        this.dragStartPos = null;
    }
}

