/**
 * The Game of Chess - Main Application Entry Point
 * Game of Thrones Edition
 */

// Wait for DOM to be ready
document.addEventListener('DOMContentLoaded', () => {
    // Initialize game components
    const canvas = document.getElementById('chess-board');
    const gameEngine = new GameEngine();
    const renderer = new Renderer(canvas, gameEngine.board);
    const inputHandler = new InputHandler(canvas, renderer, gameEngine);

    // UI Elements
    const turnIndicator = document.getElementById('turn-indicator');
    const turnIcon = turnIndicator.querySelector('.turn-icon');
    const turnText = turnIndicator.querySelector('.turn-text');
    const gameStatus = document.getElementById('game-status');
    const whiteCaptured = document.getElementById('white-captured');
    const blackCaptured = document.getElementById('black-captured');
    const moveHistory = document.getElementById('move-history');
    const restartBtn = document.getElementById('restart-btn');
    const undoBtn = document.getElementById('undo-btn');

    // Modals
    const gameOverModal = document.getElementById('game-over-modal');
    const modalTitle = document.getElementById('modal-title');
    const modalMessage = document.getElementById('modal-message');
    const modalRestartBtn = document.getElementById('modal-restart-btn');
    const promotionModal = document.getElementById('promotion-modal');
    const promotionBtns = document.querySelectorAll('.promotion-btn');

    // Set up game engine callbacks
    gameEngine.onStateChange = (state) => {
        updateUI(state);
    };

    gameEngine.onMove = (from, to, piece, captured) => {
        renderer.setLastMove({ from, to });
    };

    gameEngine.onCapture = (piece, pos) => {
        renderer.animateCapture(pos, piece);
        updateCapturedPieces();
    };

    gameEngine.onGameOver = (gameState) => {
        handleGameOver(gameState);
    };

    // Update UI functions
    function updateUI(state) {
        updateTurnIndicator(state.currentTurn);
        updateGameStatus(state.gameState);
        updateMoveHistory(state.moveHistory);

        if (state.gameState.inCheck) {
            renderer.triggerCheckAlert();
        }
    }

    function updateTurnIndicator(color) {
        turnIndicator.classList.remove('white-turn', 'black-turn');

        if (color === PieceColor.WHITE) {
            turnIndicator.classList.add('white-turn');
            turnIcon.textContent = '🐺';
            turnText.textContent = "Noble Houses' Turn";
        } else {
            turnIndicator.classList.add('black-turn');
            turnIcon.textContent = '❄️';
            turnText.textContent = "White Walkers' Turn";
        }
    }

    function updateGameStatus(gameState) {
        gameStatus.classList.remove('visible', 'check');

        if (gameState.inCheck && gameState.status === 'playing') {
            gameStatus.textContent = 'Check!';
            gameStatus.classList.add('visible', 'check');
        } else if (gameState.status !== 'playing') {
            let message = '';
            switch (gameState.status) {
                case 'checkmate':
                    const winner = gameState.winner === 'white' ? 'Noble Houses' : 'White Walkers';
                    message = `Checkmate! ${winner} Win!`;
                    break;
                case 'stalemate':
                    message = 'Stalemate! Draw.';
                    break;
            }
            gameStatus.textContent = message;
            gameStatus.classList.add('visible');
        }
    }

    function updateCapturedPieces() {
        whiteCaptured.innerHTML = '';
        blackCaptured.innerHTML = '';

        gameEngine.capturedPieces.white.forEach(piece => {
            const span = document.createElement('span');
            span.className = 'captured-piece';
            span.textContent = GoTTheme.getPieceSymbol(piece.type, piece.color);
            whiteCaptured.appendChild(span);
        });

        gameEngine.capturedPieces.black.forEach(piece => {
            const span = document.createElement('span');
            span.className = 'captured-piece';
            span.textContent = GoTTheme.getPieceSymbol(piece.type, piece.color);
            blackCaptured.appendChild(span);
        });
    }

    function updateMoveHistory(history) {
        moveHistory.innerHTML = '';

        // Group moves by pairs (white + black)
        for (let i = 0; i < history.length; i += 2) {
            const moveNumber = Math.floor(i / 2) + 1;
            const whiteMove = history[i];
            const blackMove = history[i + 1];

            const entry = document.createElement('div');
            entry.className = 'move-entry';

            const numberSpan = document.createElement('span');
            numberSpan.className = 'move-number';
            numberSpan.textContent = `${moveNumber}.`;
            entry.appendChild(numberSpan);

            const whiteSpan = document.createElement('span');
            whiteSpan.textContent = whiteMove.notation;
            entry.appendChild(whiteSpan);

            if (blackMove) {
                const blackSpan = document.createElement('span');
                blackSpan.textContent = blackMove.notation;
                entry.appendChild(blackSpan);
            }

            moveHistory.appendChild(entry);
        }

        // Scroll to bottom
        moveHistory.scrollTop = moveHistory.scrollHeight;
    }

    function handleGameOver(gameState) {
        let title, message;

        if (gameState.status === 'checkmate') {
            const winner = gameState.winner === 'white' ? 'Noble Houses' : 'White Walkers';
            title = `${winner} Victory!`;
            message = `The ${winner.toLowerCase()} have won the game of chess.`;

            if (gameState.winner === 'white') {
                title += ' 🐺';
            } else {
                title += ' ❄️';
            }
        } else if (gameState.status === 'stalemate') {
            title = 'Stalemate';
            message = 'The game ends in a draw. Both kings remain on the board.';
        }

        modalTitle.textContent = title;
        modalMessage.textContent = message;
        gameOverModal.classList.remove('hidden');

        // Trigger game over animation
        setTimeout(() => {
            renderer.triggerGameOver(gameState.winner);
        }, 500);
    }

    function showPromotionModal() {
        promotionModal.classList.remove('hidden');
    }

    function hidePromotionModal() {
        promotionModal.classList.add('hidden');
    }

    // Event listeners
    restartBtn.addEventListener('click', () => {
        gameEngine.reset();
        renderer.reset();
        inputHandler.reset();
        renderer.render();
        updateCapturedPieces();
        gameOverModal.classList.add('hidden');
    });

    modalRestartBtn.addEventListener('click', () => {
        gameEngine.reset();
        renderer.reset();
        inputHandler.reset();
        renderer.render();
        updateCapturedPieces();
        gameOverModal.classList.add('hidden');
    });

    undoBtn.addEventListener('click', () => {
        if (gameEngine.gameState.status === 'playing') {
            gameEngine.undoMove();
            renderer.render();
        }
    });

    // Promotion buttons
    promotionBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            const pieceType = btn.dataset.piece;
            gameEngine.completePromotion(pieceType);
            hidePromotionModal();
            renderer.render();
        });
    });

    // Override input handler to handle promotion
    const originalExecuteMove = inputHandler.executeMove.bind(inputHandler);
    inputHandler.executeMove = async function(from, to) {
        const moveResult = gameEngine.makeMove(from, to);

        if (moveResult.success) {
            if (moveResult.requiresPromotion) {
                showPromotionModal();
                return;
            }

            this.deselectPiece();

            // Update renderer with last move
            renderer.setLastMove({
                from: { row: from.row, col: from.col },
                to: { row: to.row, col: to.col }
            });

            // Check for check and show alert
            if (gameEngine.gameState.inCheck) {
                renderer.triggerCheckAlert();
            }

            renderer.render();
        }
    };

    // Handle canvas resize
    function resizeCanvas() {
        const container = canvas.parentElement;
        const maxWidth = Math.min(640, container.clientWidth - 40);
        const size = Math.max(320, maxWidth);

        // Maintain aspect ratio
        canvas.style.width = size + 'px';
        canvas.style.height = size + 'px';
    }

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();

    // Start the game
    gameEngine.init();
    renderer.render();

    // Start animation loop
    renderer.animationManager.start();

    // Initial UI update
    updateTurnIndicator(gameEngine.currentTurn);

    // Console welcome message
    console.log('%cThe Game of Chess', 'font-size: 24px; font-weight: bold; color: #c9a227;');
    console.log('%cGame of Thrones Edition', 'font-size: 14px; color: #e3f2fd;');
    console.log('%cWhen you play the game of chess, you win or you die.', 'font-style: italic; color: #b0bec5;');
});

